(function () {
  var COLORS = ['#3b82f6', '#22c55e', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#f97316', '#64748b'];
  var tooltipEl = null;

  function node(name, attrs, text) {
    var el = document.createElementNS('http://www.w3.org/2000/svg', name);
    Object.keys(attrs || {}).forEach(function (key) {
      el.setAttribute(key, attrs[key]);
    });
    if (text != null) el.textContent = text;
    return el;
  }

  function appendTitle(el, text) {
    if (!text) return;
    el.appendChild(node('title', null, text));
  }

  function ensureTooltip() {
    if (!tooltipEl) {
      tooltipEl = document.createElement('div');
      tooltipEl.className = 'chart-tooltip hidden';
      document.body.appendChild(tooltipEl);
    }
    return tooltipEl;
  }

  function showTooltip(event, title, lines) {
    var tip = ensureTooltip();
    var html = '';
    if (title) html += '<span class="chart-tooltip-title">' + title + '</span>';
    html += lines.map(function (line) { return '<div>' + line + '</div>'; }).join('');
    tip.innerHTML = html;
    tip.classList.remove('hidden');
    var x = event.clientX + 14;
    var y = event.clientY + 14;
    tip.style.left = x + 'px';
    tip.style.top = y + 'px';
  }

  function moveTooltip(event) {
    if (!tooltipEl || tooltipEl.classList.contains('hidden')) return;
    tooltipEl.style.left = event.clientX + 14 + 'px';
    tooltipEl.style.top = event.clientY + 14 + 'px';
  }

  function hideTooltip() {
    if (tooltipEl) tooltipEl.classList.add('hidden');
  }

  function bindTooltip(target, title, lines) {
    target.addEventListener('mouseenter', function (event) {
      showTooltip(event, title, lines);
    });
    target.addEventListener('mousemove', moveTooltip);
    target.addEventListener('mouseleave', hideTooltip);
  }

  function colorAt(index) {
    return COLORS[index % COLORS.length];
  }

  function colorAlpha(hex, alpha) {
    var raw = hex.replace('#', '');
    var full = raw.length === 3 ? raw.split('').map(function (s) { return s + s; }).join('') : raw;
    var r = parseInt(full.slice(0, 2), 16);
    var g = parseInt(full.slice(2, 4), 16);
    var b = parseInt(full.slice(4, 6), 16);
    return 'rgba(' + r + ',' + g + ',' + b + ',' + alpha + ')';
  }

  function gradient(svg, id, color, alphaStart, alphaEnd, vertical) {
    var defs = svg.querySelector('defs') || svg.insertBefore(node('defs'), svg.firstChild);
    var lg = node('linearGradient', {
      id: id,
      x1: vertical ? '0%' : '0%',
      y1: vertical ? '0%' : '0%',
      x2: vertical ? '0%' : '100%',
      y2: vertical ? '100%' : '0%'
    });
    lg.appendChild(node('stop', { offset: '0%', 'stop-color': colorAlpha(color, alphaStart) }));
    lg.appendChild(node('stop', { offset: '100%', 'stop-color': colorAlpha(color, alphaEnd) }));
    defs.appendChild(lg);
    return 'url(#' + id + ')';
  }

  function maxValue(series, stacked) {
    if (!series.length) return 100;
    if (stacked) {
      var len = Math.max.apply(null, series.map(function (s) { return (s.data || []).length; }));
      var totals = [];
      for (var i = 0; i < len; i += 1) {
        totals[i] = series.reduce(function (sum, item) { return sum + (Number((item.data || [])[i]) || 0); }, 0);
      }
      return Math.max.apply(null, totals.concat([100]));
    }
    var values = [];
    series.forEach(function (item) {
      (item.data || []).forEach(function (value) {
        values.push(Number(value) || 0);
      });
    });
    return Math.max.apply(null, values.concat([100]));
  }

  function createChart(dom) {
    return {
      dom: dom,
      option: null,
      resize: function () {
        if (this.option) this.setOption(this.option);
      },
      setOption: function (option) {
        this.option = option || {};
        render(dom, this.option);
      }
    };
  }

  function render(dom, option) {
    dom.classList.add('chart-host');
    dom.__chartInstance = dom.__chartInstance || createChart(dom);
    var rect = dom.getBoundingClientRect();
    var width = Math.max(320, Math.floor(rect.width || dom.clientWidth || 320));
    var height = Math.max(240, Math.floor(rect.height || dom.clientHeight || 240));
    var svg = node('svg', { viewBox: '0 0 ' + width + ' ' + height, width: '100%', height: '100%' });
    dom.innerHTML = '';
    dom.appendChild(svg);

    svg.appendChild(node('rect', {
      x: 0,
      y: 0,
      width: width,
      height: height,
      rx: 18,
      fill: 'rgba(7,19,43,0.45)'
    }));

    if (option.title && option.title.text) {
      svg.appendChild(node('text', { x: 18, y: 28, fill: '#dbeafe', 'font-size': 14, 'font-weight': 600 }, option.title.text));
    }

    var series = option.series || [];
    if (!series.length) return;
    var firstType = series[0].type || 'bar';
    if (firstType === 'pie') renderPie(svg, width, height, series[0].data || []);
    else if (firstType === 'line') renderLine(svg, width, height, option, series);
    else renderBar(svg, width, height, option, series);
  }

  function renderAxes(svg, width, height, horizontal, hasLegend) {
    var axis = horizontal
      ? { left: 92, right: width - 24, top: 26, bottom: height - (hasLegend ? 34 : 22) }
      : { left: 46, right: width - 18, top: 38, bottom: height - (hasLegend ? 44 : 34) };
    svg.appendChild(node('line', {
      x1: axis.left,
      y1: horizontal ? axis.top : axis.bottom,
      x2: horizontal ? axis.left : axis.right,
      y2: axis.bottom,
      stroke: 'rgba(148,163,184,.4)'
    }));
    svg.appendChild(node('line', {
      x1: axis.left,
      y1: axis.top,
      x2: axis.left,
      y2: axis.bottom,
      stroke: 'rgba(148,163,184,.4)'
    }));
    axis.plotWidth = axis.right - axis.left;
    axis.plotHeight = axis.bottom - axis.top;
    return axis;
  }

  function renderBar(svg, width, height, option, series) {
    var horizontal = option.yAxis && option.yAxis.data;
    var axis = renderAxes(svg, width, height, horizontal, series.length > 1);
    var labels = horizontal ? option.yAxis.data || [] : (option.xAxis && option.xAxis.data) || [];
    var stacked = series.length > 1 && series.some(function (s) { return !!s.stack; });
    var max = maxValue(series, stacked);
    if (horizontal) {
      var row = labels.length ? axis.plotHeight / labels.length : axis.plotHeight;
      labels.forEach(function (label, index) {
        var y = axis.top + row * index + row * 0.18;
        var xCursor = axis.left;
        var labelText = node('text', { x: 10, y: y + row * 0.34, fill: '#8aa0c5', 'font-size': 11 }, label);
        svg.appendChild(labelText);
        series.forEach(function (item, seriesIndex) {
          var value = Number((item.data || [])[index]) || 0;
          var barW = (value / max) * (axis.plotWidth - 10);
          var rect = node('rect', {
            x: xCursor,
            y: y,
            width: Math.max(barW, 2),
            height: row * 0.46,
            rx: 8,
            fill: gradient(svg, 'barh-' + seriesIndex + '-' + index, colorAt(seriesIndex), 0.95, 0.6, false),
            opacity: 0.95
          });
          appendTitle(rect, (item.name || label) + '：' + value);
          bindTooltip(rect, label, [(item.name || '数值') + '：' + value]);
          svg.appendChild(rect);
          xCursor += stacked ? barW : 0;
          if (!stacked) {
            rect.setAttribute('y', y + seriesIndex * row * 0.18);
            rect.setAttribute('height', row * 0.18);
          }
        });
      });
      return;
    }

    var slot = labels.length ? axis.plotWidth / labels.length : axis.plotWidth;
    labels.forEach(function (label, index) {
      var xBase = axis.left + slot * index;
      var yBase = axis.bottom;
      var xLabel = node('text', { x: xBase + slot / 2, y: axis.bottom + 20, 'text-anchor': 'middle', fill: '#8aa0c5', 'font-size': 11 }, label);
      svg.appendChild(xLabel);
      if (stacked) {
        var stackHeight = 0;
        series.forEach(function (item, seriesIndex) {
          var value = Number((item.data || [])[index]) || 0;
          var barH = (value / max) * (axis.plotHeight - 16);
          var rect = node('rect', {
            x: xBase + slot * 0.24,
            y: yBase - stackHeight - barH,
            width: slot * 0.52,
            height: Math.max(barH, 4),
            rx: 8,
            fill: gradient(svg, 'bars-' + seriesIndex + '-' + index, colorAt(seriesIndex), 0.96, 0.58, true),
            opacity: 0.96
          });
          appendTitle(rect, label + ' / ' + (item.name || '') + '：' + value);
          bindTooltip(rect, label, [(item.name || '数值') + '：' + value]);
          svg.appendChild(rect);
          stackHeight += barH;
        });
      } else {
        series.forEach(function (item, seriesIndex) {
          var value = Number((item.data || [])[index]) || 0;
          var barH = (value / max) * (axis.plotHeight - 16);
          var barW = Math.min(slot * 0.22, 26);
          var x = xBase + slot * 0.18 + barW * seriesIndex * 1.25;
          var rect = node('rect', {
            x: x,
            y: yBase - barH,
            width: barW,
            height: Math.max(barH, 4),
            rx: 8,
            fill: gradient(svg, 'bar-' + seriesIndex + '-' + index, colorAt(seriesIndex), 0.96, 0.58, true),
            opacity: 0.96
          });
          appendTitle(rect, label + ' / ' + (item.name || '') + '：' + value);
          bindTooltip(rect, label, [(item.name || '数值') + '：' + value]);
          svg.appendChild(rect);
          if (slot > 70) {
            var vText = node('text', { x: x + barW / 2, y: yBase - barH - 6, 'text-anchor': 'middle', fill: '#dbeafe', 'font-size': 10 }, value);
            svg.appendChild(vText);
          }
        });
      }
    });
    renderLegend(svg, series, width, height);
  }

  function renderLine(svg, width, height, option, series) {
    var axis = renderAxes(svg, width, height, false, series.length > 1);
    var labels = (option.xAxis && option.xAxis.data) || [];
    var max = maxValue(series, false);
    var step = labels.length > 1 ? axis.plotWidth / (labels.length - 1) : axis.plotWidth;

    labels.forEach(function (label, index) {
      svg.appendChild(node('text', { x: axis.left + step * index, y: axis.bottom + 20, 'text-anchor': 'middle', fill: '#8aa0c5', 'font-size': 11 }, label));
    });

    series.forEach(function (item, seriesIndex) {
      var points = [];
      var areaPoints = [];
      (item.data || []).forEach(function (value, index) {
        var numeric = Number(value) || 0;
        var x = axis.left + step * index;
        var y = axis.bottom - (numeric / max) * (axis.plotHeight - 16);
        points.push(x + ',' + y);
        areaPoints.push(x + ',' + y);
        var circle = node('circle', { cx: x, cy: y, r: 4, fill: colorAt(seriesIndex), stroke: '#dbeafe', 'stroke-width': 1.5 });
        appendTitle(circle, (item.name || '') + ' ' + (labels[index] || '') + '：' + numeric);
        bindTooltip(circle, labels[index] || '', [(item.name || '数值') + '：' + numeric]);
        svg.appendChild(circle);
        if (step > 70) {
          svg.appendChild(node('text', { x: x, y: y - 8, 'text-anchor': 'middle', fill: '#dbeafe', 'font-size': 10 }, numeric));
        }
      });
      if (item.areaStyle) {
        areaPoints.push(axis.left + step * ((item.data || []).length - 1) + ',' + axis.bottom);
        areaPoints.push(axis.left + ',' + axis.bottom);
        svg.appendChild(node('polygon', {
          points: areaPoints.join(' '),
          fill: gradient(svg, 'area-' + seriesIndex, colorAt(seriesIndex), 0.28, 0.02, true),
          opacity: 0.16
        }));
      }
      svg.appendChild(node('polyline', {
        points: points.join(' '),
        fill: 'none',
        stroke: colorAt(seriesIndex),
        'stroke-width': 3,
        'stroke-linecap': 'round',
        'stroke-linejoin': 'round'
      }));
    });
    renderLegend(svg, series, width, height);
  }

  function renderPie(svg, width, height, items) {
    var total = items.reduce(function (sum, item) { return sum + (Number(item.value) || 0); }, 0) || 1;
    var centerX = width * 0.66;
    var centerY = height * 0.55;
    var radius = Math.min(width, height) * 0.22;
    var current = -90;
    var legendY = 44;

    items.forEach(function (item, index) {
      var value = Number(item.value) || 0;
      var angle = (value / total) * 360;
      var start = current * Math.PI / 180;
      var end = (current + angle) * Math.PI / 180;
      var startX = centerX + Math.cos(start) * radius;
      var startY = centerY + Math.sin(start) * radius;
      var endX = centerX + Math.cos(end) * radius;
      var endY = centerY + Math.sin(end) * radius;
      var largeArc = angle > 180 ? 1 : 0;
      var path = ['M', centerX, centerY, 'L', startX, startY, 'A', radius, radius, 0, largeArc, 1, endX, endY, 'Z'].join(' ');
      var sector = node('path', { d: path, fill: colorAt(index), opacity: 0.96 });
      appendTitle(sector, (item.name || '分类') + '：' + value);
      bindTooltip(sector, item.name || '分类', ['数量：' + value, '占比：' + ((value / total) * 100).toFixed(1) + '%']);
      svg.appendChild(sector);
      svg.appendChild(node('rect', { x: 24, y: legendY - 10, width: 10, height: 10, rx: 2, fill: colorAt(index) }));
      svg.appendChild(node('text', { x: 40, y: legendY, fill: '#dbeafe', 'font-size': 12 }, (item.name || '分类') + '  ' + value));
      legendY += 20;
      current += angle;
    });
  }

  function renderLegend(svg, series, width, height) {
    if (!series || series.length <= 1) return;
    var x = 22;
    var y = height - 18;
    series.forEach(function (item, index) {
      svg.appendChild(node('circle', { cx: x, cy: y - 4, r: 4, fill: colorAt(index) }));
      svg.appendChild(node('text', { x: x + 9, y: y, fill: '#8aa0c5', 'font-size': 11 }, item.name || ('系列' + (index + 1))));
      x += 86;
    });
  }

  window.echarts = {
    init: function (dom) {
      var chart = dom.__chartInstance || createChart(dom);
      dom.__chartInstance = chart;
      return chart;
    },
    graphic: { LinearGradient: function () {} }
  };

  window.addEventListener('resize', function () {
    document.querySelectorAll('.chart-host').forEach(function (dom) {
      if (dom.__chartInstance) dom.__chartInstance.resize();
    });
  });
})();
